  1→/**
  2→ * Claude Code Session Provider
  3→ *
  4→ * Apparatus plugin that implements AnimatorSessionProvider for the
  5→ * Claude Code CLI. The Animator discovers this via guild config:
  6→ *
  7→ *   guild.json["animator"]["sessionProvider"] = "claude-code"
  8→ *
  9→ * Launches sessions via the `claude` CLI in autonomous mode (--print)
 10→ * with --output-format stream-json for structured telemetry.
 11→ *
 12→ * Key design choice: uses async spawn() instead of spawnSync().
 13→ * This is required for stream-json transcript parsing, timeout enforcement,
 14→ * and future concurrent session support.
 15→ */
 16→
 17→import { spawn } from 'node:child_process';
 18→import fs from 'node:fs';
 19→import os from 'node:os';
 20→import path from 'node:path';
 21→
 22→import type { Plugin } from '@shardworks/nexus-core';
 23→import { guild } from '@shardworks/nexus-core';
 24→import type {
 25→  AnimatorSessionProvider,
 26→  SessionProviderConfig,
 27→  SessionProviderResult,
 28→  SessionChunk,
 29→} from '@shardworks/animator-apparatus';
 30→
 31→import { startMcpHttpServer } from './mcp-server.ts';
 32→import type { McpHttpHandle } from './mcp-server.ts';
 33→import { launchDetached } from './detached.ts';
 34→
 35→// ── Session File Preparation ────────────────────────────────────────────
 36→
 37→/** Prepared session files in a temp directory. */
 38→interface PreparedSession {
 39→  tmpDir: string;
 40→  args: string[];
 41→  /** If an MCP server was started, this handle closes it. */
 42→  mcpHandle?: McpHttpHandle;
 43→}
 44→
 45→/**
 46→ * Prepare session files and build base CLI args.
 47→ *
 48→ * Writes system prompt to a temp directory. Builds the base args array
 49→ * including --resume support. When tools are provided, starts an
 50→ * in-process MCP HTTP server and writes --mcp-config.
 51→ *
 52→ * Caller is responsible for cleaning up tmpDir and calling mcpHandle.close().
 53→ */
 54→async function prepareSession(config: SessionProviderConfig): Promise<PreparedSession> {
 55→  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-session-'));
 56→
 57→  const args: string[] = [
 58→    '--setting-sources', 'user',
 59→    '--dangerously-skip-permissions',
 60→    '--model', config.model,
 61→  ];
 62→
 63→  if (config.systemPrompt) {
 64→    const systemPromptPath = path.join(tmpDir, 'system-prompt.md');
 65→    fs.writeFileSync(systemPromptPath, config.systemPrompt);
 66→    args.push('--system-prompt-file', systemPromptPath);
 67→  }
 68→
 69→  // Resume an existing conversation
 70→  if (config.conversationId) {
 71→    args.push('--resume', config.conversationId);
 72→  }
 73→
 74→  // Tool-equipped session: start MCP HTTP server, write --mcp-config
 75→  let mcpHandle: McpHttpHandle | undefined;
 76→
 77→  if (config.tools && config.tools.length > 0) {
 78→    const tools = config.tools.map((rt) => rt.definition);
 79→    mcpHandle = await startMcpHttpServer(tools);
 80→
 81→    const mcpConfig = {
 82→      mcpServers: {
 83→        'nexus-guild': {
 84→          type: 'sse',
 85→          url: mcpHandle.url,
 86→        },
 87→      },
 88→    };
 89→
 90→    const mcpConfigPath = path.join(tmpDir, 'mcp-config.json');
 91→    fs.writeFileSync(mcpConfigPath, JSON.stringify(mcpConfig));
 92→    args.push('--mcp-config', mcpConfigPath, '--strict-mcp-config');
 93→  }
 94→
 95→  return { tmpDir, args, mcpHandle };
 96→}
 97→
 98→// ── Output extraction ───────────────────────────────────────────────
 99→
100→/**
101→ * Extract the final assistant text from a transcript.
102→ *
103→ * Walks the transcript backwards to find the last `assistant` message
104→ * and concatenates its text content blocks.
105→ *
106→ * @internal Exported for testing only.
107→ */
108→export function extractFinalAssistantText(transcript: Record<string, unknown>[]): string | undefined {
109→  for (let i = transcript.length - 1; i >= 0; i--) {
110→    const msg = transcript[i]!;
111→    if (msg.type !== 'assistant') continue;
112→
113→    const message = msg.message as Record<string, unknown> | undefined;
114→    const content = message?.content as Array<Record<string, unknown>> | undefined;
115→    if (!content) continue;
116→
117→    const text = content
118→      .filter((block) => block.type === 'text' && typeof block.text === 'string')
119→      .map((block) => block.text as string)
120→      .join('');
121→
122→    return text || undefined;
123→  }
124→  return undefined;
125→}
126→
127→// ── Result builder ──────────────────────────────────────────────────
128→
129→function buildResult(raw: StreamJsonResult): SessionProviderResult {
130→  const status = raw.exitCode === 0 ? 'completed' as const : 'failed' as const;
131→  return {
132→    status,
133→    exitCode: raw.exitCode,
134→    error: status === 'failed' ? `claude exited with code ${raw.exitCode}` : undefined,
135→    costUsd: raw.costUsd,
136→    tokenUsage: raw.tokenUsage,
137→    providerSessionId: raw.providerSessionId,
138→    transcript: raw.transcript,
139→    output: extractFinalAssistantText(raw.transcript),
140→    signal: raw.signal,
141→  };
142→}
143→
144→// ── Provider implementation ──────────────────────────────────────────
145→
146→const provider: AnimatorSessionProvider = {
147→  name: 'claude-code',
148→
149→  async cancel(cancelMetadata: Record<string, unknown>): Promise<void> {
150→    const pid = cancelMetadata.pid as number | undefined;
151→    if (pid === undefined) return;
152→    try {
153→      process.kill(pid, 'SIGTERM');
154→    } catch (err: unknown) {
155→      if ((err as NodeJS.ErrnoException).code === 'ESRCH') {
156→        // Process already dead — expected for race conditions. Silent no-op.
157→        return;
158→      }
159→      throw err;
160→    }
161→  },
162→
163→  launch(config: SessionProviderConfig): {
164→    chunks: AsyncIterable<SessionChunk>;
165→    result: Promise<SessionProviderResult>;
166→    processInfo?: Promise<Record<string, unknown>>;
167→  } {
168→    // Detached mode is the default: spawn a babysitter process that survives
169→    // guild restarts, hosts the MCP server, spawns claude, streams transcripts
170→    // to SQLite, and reports lifecycle events via HTTP.
171→    //
172→    // Escape hatch: guild.json["animator"]["detached"] = false opts out and
173→    // runs claude in-process (attached mode) for debugging.
174→    let detached = true;
175→    try {
176→      const animatorConfig = guild().guildConfig().animator as
177→        | { detached?: boolean }
178→        | undefined;
179→      if (animatorConfig?.detached === false) detached = false;
180→    } catch {
181→      // No guild bound (e.g. unit tests) — fall back to detached default.
182→    }
183→    return detached ? launchDetached(config) : launchAttached(config);
184→  },
185→};
186→
187→// ── Attached launch (preserved for debugging / non-detached mode) ──────
188→
189→/**
190→ * Launch a session in attached mode — claude as a direct child process.
191→ *
192→ * Preserved for debugging and potential future "attached mode" escape hatch.
193→ * Not currently wired into the provider, but all supporting code is kept.
194→ *
195→ * @internal
196→ */
197→export function launchAttached(config: SessionProviderConfig): {
198→  chunks: AsyncIterable<SessionChunk>;
199→  result: Promise<SessionProviderResult>;
200→  processInfo?: Promise<Record<string, unknown>>;
201→} {
202→    // prepareSession is async (MCP server start), so we wrap the launch
203→    // in a promise. The chunks iterable bridges the async gap — it waits
204→    // for prep to complete before yielding.
205→
206→    let chunkResolve: (() => void) | null = null;
207→    let innerChunks: AsyncIterable<SessionChunk> | null = null;
208→    let innerIterator: AsyncIterator<SessionChunk> | null = null;
209→    let prepDone = false;
210→    let prepError: Error | null = null;
211→    let done = false;
212→
213→    // processInfo promise — resolved with { pid } once the process spawns.
214→    let resolveProcessInfo: ((info: Record<string, unknown>) => void) | null = null;
215→    let rejectProcessInfo: ((err: Error) => void) | null = null;
216→    const processInfo = new Promise<Record<string, unknown>>((resolve, reject) => {
217→      resolveProcessInfo = resolve;
218→      rejectProcessInfo = reject;
219→    });
220→
221→    const result = prepareSession(config).then(async ({ tmpDir, args, mcpHandle }) => {
222→      // Autonomous mode: prompt piped via stdin (--print - reads from stdin).
223→      // This avoids Commander parsing issues when the prompt starts with '-'
224→      // (e.g. YAML frontmatter '---') and also avoids OS arg length limits.
225→      const prompt = config.initialPrompt ?? '';
226→      args.push(
227→        '--print', '-',
228→        '--output-format', 'stream-json',
229→        '--verbose',
230→      );
231→
232→      const cleanup = async () => {
233→        await mcpHandle?.close().catch(() => {});
234→        fs.rmSync(tmpDir, { recursive: true, force: true });
235→      };
236→
237→      try {
238→        if (config.streaming) {
239→          const spawned = spawnClaudeStreamingJson(args, config.cwd, config.environment, prompt);
240→          resolveProcessInfo!({ pid: spawned.pid });
241→          innerChunks = spawned.chunks;
242→          prepDone = true;
243→          if (chunkResolve) { chunkResolve(); chunkResolve = null; }
244→
245→          const raw = await spawned.result;
246→          await cleanup();
247→          return buildResult(raw);
248→        }
249→
250→        // Non-streaming
251→        const { result: spawnResult, pid } = spawnClaudeStreamJson(args, config.cwd, config.environment, prompt);
252→        resolveProcessInfo!({ pid });
253→        prepDone = true;
254→        done = true;
255→        if (chunkResolve) { chunkResolve(); chunkResolve = null; }
256→
257→        const raw = await spawnResult;
258→        await cleanup();
259→        return buildResult(raw);
260→      } catch (err) {
261→        await cleanup();
262→        throw err;
263→      }
264→    }).catch((err) => {
265→      // If prep itself failed, unblock the chunk iterator and processInfo
266→      prepError = err instanceof Error ? err : new Error(String(err));
267→      prepDone = true;
268→      done = true;
269→      if (chunkResolve) { chunkResolve(); chunkResolve = null; }
270→      rejectProcessInfo!(prepError);
271→      throw err;
272→    });
273→
274→    // Chunks iterable that bridges the async prep gap. In non-streaming
275→    // mode or on error, it completes immediately with no items.
276→    const chunks: AsyncIterable<SessionChunk> = {
277→      [Symbol.asyncIterator]() {
278→        return {
279→          async next(): Promise<IteratorResult<SessionChunk>> {
280→            // Wait for prep to complete
281→            while (!prepDone) {
282→              await new Promise<void>((resolve) => { chunkResolve = resolve; });
283→            }
284→
285→            if (prepError || done) {
286→              return { value: undefined as unknown as SessionChunk, done: true };
287→            }
288→
289→            // Delegate to inner streaming iterator
290→            if (innerChunks && !innerIterator) {
291→              innerIterator = innerChunks[Symbol.asyncIterator]();
292→            }
293→
294→            if (innerIterator) {
295→              return innerIterator.next();
296→            }
297→
298→            return { value: undefined as unknown as SessionChunk, done: true };
299→          },
300→        };
301→      },
302→    };
303→
304→    return { chunks, result, processInfo };
305→}
306→
307→// ── Apparatus export ─────────────────────────────────────────────────
308→
309→/**
310→ * Create the Claude Code session provider apparatus.
311→ *
312→ * The apparatus has no startup logic — it just provides the
313→ * AnimatorSessionProvider implementation. The Animator looks it up
314→ * via guild().apparatus('claude-code').
315→ */
316→export function createClaudeCodeProvider(): Plugin {
317→  return {
318→    apparatus: {
319→      requires: [],
320→      provides: provider,
321→
322→      start() {
323→        // No startup work — the provider is stateless.
324→      },
325→    },
326→  };
327→}
328→
329→export default createClaudeCodeProvider();
330→
331→// ── MCP server re-exports ───────────────────────────────────────────
332→// The MCP server module is used by the session provider to attach tools
333→// to sessions via --mcp-config, and can be imported directly for
334→// testing or custom integrations.
335→
336→export { createMcpServer, startMcpHttpServer } from './mcp-server.ts';
337→export type { McpHttpHandle } from './mcp-server.ts';
338→
339→// ── Spawn helpers ────────────────────────────────────────────────────
340→
341→/** Parsed result from stream-json output. @internal */
342→export interface StreamJsonResult {
343→  exitCode: number;
344→  transcript: Record<string, unknown>[];
345→  costUsd?: number;
346→  tokenUsage?: {
347→    inputTokens: number;
348→    outputTokens: number;
349→    cacheReadTokens?: number;
350→    cacheWriteTokens?: number;
351→  };
352→  providerSessionId?: string;
353→  /** Process signal name if killed by signal (e.g. 'SIGTERM'). */
354→  signal?: string;
355→}
356→
357→/**
358→ * Parse a single NDJSON message from stream-json output.
359→ *
360→ * Returns parsed chunks for streaming and accumulates data into the
361→ * provided accumulators (transcript, metrics).
362→ *
363→ * @internal Exported for testing only.
364→ */
365→export function parseStreamJsonMessage(
366→  msg: Record<string, unknown>,
367→  acc: {
368→    transcript: Record<string, unknown>[];
369→    costUsd?: number;
370→    tokenUsage?: StreamJsonResult['tokenUsage'];
371→    providerSessionId?: string;
372→  },
373→): SessionChunk[] {
374→  const chunks: SessionChunk[] = [];
375→
376→  if (msg.type === 'assistant') {
377→    acc.transcript.push(msg);
378→
379→    const message = msg.message as Record<string, unknown> | undefined;
380→    if (message) {
381→      const content = message.content as Array<Record<string, unknown>> | undefined;
382→      if (content) {
383→        for (const block of content) {
384→          if (block.type === 'text' && typeof block.text === 'string') {
385→            chunks.push({ type: 'text', text: block.text });
386→          } else if (block.type === 'tool_use' && typeof block.name === 'string') {
387→            chunks.push({ type: 'tool_use', tool: block.name });
388→          }
389→        }
390→      }
391→    }
392→  } else if (msg.type === 'user') {
393→    acc.transcript.push(msg);
394→
395→    const content = (msg as Record<string, unknown>).content as Array<Record<string, unknown>> | undefined;
396→    if (content) {
397→      for (const block of content) {
398→        if (block.type === 'tool_result' && typeof block.tool_use_id === 'string') {
399→          chunks.push({ type: 'tool_result', tool: String(block.tool_use_id) });
400→        }
401→      }
402→    }
403→  } else if (msg.type === 'result') {
404→    acc.costUsd = typeof msg.total_cost_usd === 'number' ? msg.total_cost_usd : undefined;
405→    acc.providerSessionId = typeof msg.session_id === 'string' ? msg.session_id : undefined;
406→
407→    const usage = msg.usage as Record<string, unknown> | undefined;
408→    if (usage) {
409→      acc.tokenUsage = {
410→        inputTokens: (typeof usage.input_tokens === 'number' ? usage.input_tokens : 0),
411→        outputTokens: (typeof usage.output_tokens === 'number' ? usage.output_tokens : 0),
412→        cacheReadTokens: typeof usage.cache_read_input_tokens === 'number'
413→          ? usage.cache_read_input_tokens : undefined,
414→        cacheWriteTokens: typeof usage.cache_creation_input_tokens === 'number'
415→          ? usage.cache_creation_input_tokens : undefined,
416→      };
417→    }
418→  }
419→
420→  return chunks;
421→}
422→
423→/**
424→ * Process NDJSON buffer, calling handler for each complete line.
425→ * Returns the remaining incomplete buffer.
426→ *
427→ * @internal Exported for testing only.
428→ */
429→export function processNdjsonBuffer(
430→  buffer: string,
431→  handler: (msg: Record<string, unknown>) => void,
432→): string {
433→  let newlineIdx: number;
434→  while ((newlineIdx = buffer.indexOf('\n')) !== -1) {
435→    const line = buffer.slice(0, newlineIdx).trim();
436→    buffer = buffer.slice(newlineIdx + 1);
437→
438→    if (!line) continue;
439→
440→    try {
441→      const msg = JSON.parse(line) as Record<string, unknown>;
442→      handler(msg);
443→    } catch {
444→      // Non-JSON line — ignore
445→    }
446→  }
447→  return buffer;
448→}
449→
450→/**
451→ * Spawn Claude in autonomous mode with --output-format stream-json.
452→ *
453→ * Captures stdout (NDJSON lines), parses each line to extract:
454→ * - assistant messages → transcript
455→ * - result message → cost, token usage, session ID
456→ *
457→ * Forwards assistant text content to stderr so it's visible during execution.
458→ */
459→function spawnClaudeStreamJson(args: string[], cwd: string, env?: Record<string, string>, stdinData?: string): { result: Promise<StreamJsonResult>; pid: number } {
460→  const proc = spawn('claude', args, {
461→    cwd,
462→    stdio: ['pipe', 'pipe', 'inherit'],
463→    env: { ...process.env, ...env },
464→  });
465→
466→  // Pipe prompt via stdin (--print - reads from stdin)
467→  if (stdinData !== undefined) {
468→    proc.stdin!.write(stdinData);
469→    proc.stdin!.end();
470→  }
471→
472→  const acc: {
473→    transcript: Record<string, unknown>[];
474→    costUsd?: number;
475→    tokenUsage?: StreamJsonResult['tokenUsage'];
476→    providerSessionId?: string;
477→  } = { transcript: [] };
478→
479→  let buffer = '';
480→
481→  proc.stdout!.on('data', (chunk: Buffer) => {
482→    buffer += chunk.toString();
483→    buffer = processNdjsonBuffer(buffer, (msg) => {
484→      const chunks = parseStreamJsonMessage(msg, acc);
485→      for (const c of chunks) {
486→        if (c.type === 'text') {
487→          process.stderr.write(c.text);
488→        }
489→      }
490→    });
491→  });
492→
493→  const result = new Promise<StreamJsonResult>((resolve, reject) => {
494→    proc.on('error', (err) => {
495→      reject(new Error(`Failed to spawn claude: ${err.message}`));
496→    });
497→
498→    proc.on('close', (code, signal) => {
499→      if (acc.transcript.length > 0) {
500→        process.stderr.write('\n');
501→      }
502→
503→      resolve({
504→        exitCode: code ?? 1,
505→        transcript: acc.transcript,
506→        costUsd: acc.costUsd,
507→        tokenUsage: acc.tokenUsage,
508→        providerSessionId: acc.providerSessionId,
509→        signal: signal ?? undefined,
510→      });
511→    });
512→  });
513→
514→  return { result, pid: proc.pid! };
515→}
516→
517→/**
518→ * Spawn Claude with streaming — yields SessionChunks as they arrive
519→ * while also accumulating the full result.
520→ *
521→ * Returns an async iterable of chunks for real-time consumption and
522→ * a promise for the final StreamJsonResult.
523→ */
524→function spawnClaudeStreamingJson(args: string[], cwd: string, env?: Record<string, string>, stdinData?: string): {
525→  chunks: AsyncIterable<SessionChunk>;
526→  result: Promise<StreamJsonResult>;
527→  pid: number;
528→} {
529→  const chunkQueue: SessionChunk[] = [];
530→  let chunkResolve: (() => void) | null = null;
531→  let done = false;
532→
533→  const acc: {
534→    transcript: Record<string, unknown>[];
535→    costUsd?: number;
536→    tokenUsage?: StreamJsonResult['tokenUsage'];
537→    providerSessionId?: string;
538→  } = { transcript: [] };
539→
540→  const proc = spawn('claude', args, {
541→    cwd,
542→    stdio: ['pipe', 'pipe', 'inherit'],
543→    env: { ...process.env, ...env },
544→  });
545→
546→  // Pipe prompt via stdin (--print - reads from stdin)
547→  if (stdinData !== undefined) {
548→    proc.stdin!.write(stdinData);
549→    proc.stdin!.end();
550→  }
551→
552→  let buffer = '';
553→
554→  proc.stdout!.on('data', (chunk: Buffer) => {
555→    buffer += chunk.toString();
556→    buffer = processNdjsonBuffer(buffer, (msg) => {
557→      const newChunks = parseStreamJsonMessage(msg, acc);
558→      for (const c of newChunks) {
559→        if (c.type === 'text') {
560→          process.stderr.write(c.text);
561→        }
562→      }
563→      if (newChunks.length > 0) {
564→        chunkQueue.push(...newChunks);
565→        if (chunkResolve) {
566→          chunkResolve();
567→          chunkResolve = null;
568→        }
569→      }
570→    });
571→  });
572→
573→  const result = new Promise<StreamJsonResult>((resolve, reject) => {
574→    proc.on('error', (err) => {
575→      done = true;
576→      if (chunkResolve) { chunkResolve(); chunkResolve = null; }
577→      reject(new Error(`Failed to spawn claude: ${err.message}`));
578→    });
579→
580→    proc.on('close', (code, signal) => {
581→      if (acc.transcript.length > 0) {
582→        process.stderr.write('\n');
583→      }
584→      done = true;
585→      if (chunkResolve) { chunkResolve(); chunkResolve = null; }
586→      resolve({
587→        exitCode: code ?? 1,
588→        transcript: acc.transcript,
589→        costUsd: acc.costUsd,
590→        tokenUsage: acc.tokenUsage,
591→        providerSessionId: acc.providerSessionId,
592→        signal: signal ?? undefined,
593→      });
594→    });
595→  });
596→
597→  const chunks: AsyncIterable<SessionChunk> = {
598→    [Symbol.asyncIterator]() {
599→      return {
600→        async next(): Promise<IteratorResult<SessionChunk>> {
601→          while (true) {
602→            if (chunkQueue.length > 0) {
603→              return { value: chunkQueue.shift()!, done: false };
604→            }
605→            if (done) {
606→              return { value: undefined as unknown as SessionChunk, done: true };
607→            }
608→            await new Promise<void>((resolve) => { chunkResolve = resolve; });
609→          }
610→        },
611→      };
612→    },
613→  };
614→
615→  return { chunks, result, pid: proc.pid! };
616→}
