248→// ── Detached launch ────────────────────────────────────────────────────
249→
250→/**
251→ * Build a SessionProviderResult from a terminal SessionDoc.
252→ */
253→function docToProviderResult(doc: SessionDoc): SessionProviderResult {
254→  const status: SessionProviderResult['status'] =
255→    doc.status === 'running' || doc.status === 'pending'
256→      ? 'failed'
257→      : doc.status;
258→  return {
259→    status,
260→    exitCode: doc.exitCode ?? 1,
261→    error: doc.error,
262→    providerSessionId: doc.providerSessionId,
263→    tokenUsage: doc.tokenUsage,
264→    costUsd: doc.costUsd,
265→    output: doc.output,
266→    // Note: transcript is not included here — it's in the transcripts book.
267→    // The babysitter writes it directly to SQLite.
268→  };
269→}
270→
271→/**
272→ * Launch a detached babysitter process.
273→ *
274→ * Returns { chunks, result, processInfo } where:
275→ * - chunks: completes immediately (empty) — transcripts stream to SQLite
276→ * - result: polls sessions book for terminal status
277→ * - processInfo: polls SessionDoc for cancelMetadata (contains claude PID)
278→ */
279→export function launchDetached(
280→  config: SessionProviderConfig,
