/**
 * Detached session launch — spawns a babysitter process instead of claude directly.
 *
 * The babysitter runs as a detached process that survives guild restarts.
 * It hosts the MCP server, spawns claude, streams transcripts to SQLite,
 * and reports lifecycle events to the guild via HTTP.
 *
 * See: docs/architecture/detached-sessions.md
 */

import { spawn } from 'node:child_process';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';

import { z } from 'zod';

import { guild } from '@shardworks/nexus-core';
import type {
  SessionProviderConfig,
  SessionProviderResult,
  SessionChunk,
  SessionDoc,
} from '@shardworks/animator-apparatus';
import type { StacksApi, ReadOnlyBook, Book } from '@shardworks/stacks-apparatus';
import type { ResolvedTool } from '@shardworks/tools-apparatus';

import type { BabysitterConfig, SerializedTool } from './babysitter.ts';

// ── Constants ──────────────────────────────────────────────────────────

/** Default poll interval for session status (ms). */
const POLL_INTERVAL_MS = 5_000;
/** Default poll timeout — generous to allow long-running sessions (24h). */
const POLL_TIMEOUT_MS = 24 * 60 * 60 * 1_000;
/** Default tool server port (matches Instrumentarium default). */
const DEFAULT_TOOL_SERVER_PORT = 7471;

// ── Tool serialization ─────────────────────────────────────────────────

/**
 * Serialize a ResolvedTool's Zod params to a SerializedTool with JSON Schema.
 *
 * Uses Zod 4's built-in `z.toJSONSchema()` to convert the params schema.
 * The resulting JSON Schema is what the babysitter's MCP proxy server
 * advertises to claude via tools/list.
 */
export function serializeTool(rt: ResolvedTool): SerializedTool {
  const def = rt.definition;
  const jsonSchema = z.toJSONSchema(def.params) as Record<string, unknown>;

  // z.toJSONSchema returns a full JSON Schema object with type, properties, etc.
  // We extract the inner properties/required for the MCP tool registration,
  // since the babysitter wraps it in { type: 'object', ...params }.
  const { type: _type, $schema: _schema, ...params } = jsonSchema;

  return {
    name: def.name,
    description: def.description,
    params,
  };
}

/**
 * Serialize an array of ResolvedTools to SerializedTools.
 */
export function serializeTools(tools: ResolvedTool[]): SerializedTool[] {
  return tools.map(serializeTool);
}

// ── Guild config resolution ────────────────────────────────────────────

/** Resolve the guild's Tool HTTP API URL. */
export function resolveGuildToolUrl(): string {
  const g = guild();
  // Match the Instrumentarium's port resolution logic:
  // guild.json["tools"]["serverPort"] → default 7471
  const toolsConfig = g.config<{ serverPort?: number }>('tools');
  const port = toolsConfig?.serverPort ?? DEFAULT_TOOL_SERVER_PORT;
  return `http://127.0.0.1:${port}`;
}

/** Resolve the path to the guild's SQLite database. */
export function resolveDbPath(): string {
  const g = guild();
  return path.join(g.home, '.nexus', 'nexus.db');
}

/**
 * Resolve the babysitter script path, picking the .ts source or .js compiled
 * output to match how this module itself was loaded.
 *
 * - In compiled output (`dist/detached.js`) → returns `dist/babysitter.js`.
 * - In source mode (`src/detached.ts` via --experimental-transform-types) →
 *   returns `src/babysitter.ts`.
 *
 * The detection is by extension of the current module's URL. Without this,
 * source-mode runs (e.g. `nsg start --foreground` in dev) try to spawn a
 * non-existent `babysitter.js` and the babysitter dies with MODULE_NOT_FOUND
 * before it can call session-running.
 */
export function resolveBabysitterPath(): string {
  const dir = import.meta.dirname ?? path.dirname(new URL(import.meta.url).pathname);
  const isSource = import.meta.url.endsWith('.ts');
  return path.join(dir, isSource ? 'babysitter.ts' : 'babysitter.js');
}

// ── BabysitterConfig builder ───────────────────────────────────────────

export interface DetachedLaunchOptions {
  /** Override babysitter script path (for testing). */
  babysitterPath?: string;
  /** Override guild tool URL (for testing). */
  guildToolUrl?: string;
  /** Override database path (for testing). */
  dbPath?: string;
  /** Override poll interval in ms (for testing). */
  pollIntervalMs?: number;
  /** Override poll timeout in ms (for testing). */
  pollTimeoutMs?: number;
  /** Override sessions book (for testing). */
  sessionsBook?: ReadOnlyBook<SessionDoc>;
  /** Override spawn function (for testing). */
  spawnFn?: typeof spawn;
  /** Session metadata from the AnimateRequest. */
  metadata?: Record<string, unknown>;
}

/**
 * Build a BabysitterConfig from the provider's SessionProviderConfig.
 *
 * Serializes tools from Zod schemas to JSON Schema, resolves guild
 * infrastructure paths, and constructs the base CLI args for claude.
 */
export function buildBabysitterConfig(
  config: SessionProviderConfig,
  opts?: DetachedLaunchOptions,
): BabysitterConfig {
  // Build claude CLI args (the babysitter adds --print, --output-format,
  // --verbose, --mcp-config).
  const claudeArgs: string[] = [
    '--setting-sources', 'user',
    '--dangerously-skip-permissions',
    '--model', config.model,
  ];

  // System prompt: write to a temp file and include --system-prompt-file in claudeArgs.
  // The file persists for the session duration — acceptable for detached sessions.
  // The babysitter's tmpDir cleanup doesn't touch this, but OS tmp cleanup handles it.
  if (config.systemPrompt) {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-detached-'));
    const systemPromptPath = path.join(tmpDir, 'system-prompt.md');
    fs.writeFileSync(systemPromptPath, config.systemPrompt);
    claudeArgs.push('--system-prompt-file', systemPromptPath);
  }

  // Resume support
  if (config.conversationId) {
    claudeArgs.push('--resume', config.conversationId);
  }

  return {
    sessionId: config.sessionId,
    guildToolUrl: opts?.guildToolUrl ?? resolveGuildToolUrl(),
    dbPath: opts?.dbPath ?? resolveDbPath(),
    claudeArgs,
    cwd: config.cwd,
    env: config.environment ?? {},
    prompt: config.initialPrompt ?? '',
    tools: serializeTools(config.tools ?? []),
    startedAt: new Date().toISOString(),
    provider: 'claude-code',
    metadata: opts?.metadata,
  };
}

// ── Polling helpers ────────────────────────────────────────────────────

/**
 * Poll the sessions book until the session reaches a terminal status.
 *
 * Returns the SessionDoc when status is no longer 'running'.
 * Throws on timeout.
 */
export async function pollForTerminalStatus(
  sessionsBook: ReadOnlyBook<SessionDoc>,
  sessionId: string,
  pollIntervalMs: number = POLL_INTERVAL_MS,
  pollTimeoutMs: number = POLL_TIMEOUT_MS,
): Promise<SessionDoc> {
  const deadline = Date.now() + pollTimeoutMs;

  while (Date.now() < deadline) {
    const doc = await sessionsBook.get(sessionId);

    if (doc && doc.status !== 'running' && doc.status !== 'pending') {
      return doc;
    }

    const remaining = deadline - Date.now();
    if (remaining <= 0) break;

    await new Promise((resolve) => setTimeout(resolve, Math.min(pollIntervalMs, remaining)));
  }

  throw new Error(
    `Session ${sessionId} did not reach terminal status within ${pollTimeoutMs}ms`,
  );
}

/**
 * Poll the sessions book until cancelMetadata.pid is available.
 *
 * The babysitter reports the claude PID via the session-running tool,
 * which writes cancelMetadata to the SessionDoc. We poll for it.
 */
export async function pollForProcessInfo(
  sessionsBook: ReadOnlyBook<SessionDoc>,
  sessionId: string,
  pollIntervalMs: number = POLL_INTERVAL_MS,
  pollTimeoutMs: number = 60_000,
): Promise<Record<string, unknown>> {
  const deadline = Date.now() + pollTimeoutMs;

  while (Date.now() < deadline) {
    const doc = await sessionsBook.get(sessionId);

    if (doc?.cancelMetadata) {
      return doc.cancelMetadata;
    }

    // If the session already terminated, return empty (no process to cancel)
    if (doc && doc.status !== 'running' && doc.status !== 'pending') {
      return {};
    }

    const remaining = deadline - Date.now();
    if (remaining <= 0) break;

    await new Promise((resolve) => setTimeout(resolve, Math.min(pollIntervalMs, remaining)));
  }

  // Timeout — return empty rather than throwing. The babysitter PID is a
  // fallback anyway, and the session might still be starting up.
  return {};
}

// ── Detached launch ────────────────────────────────────────────────────

/**
 * Build a SessionProviderResult from a terminal SessionDoc.
 */
function docToProviderResult(doc: SessionDoc): SessionProviderResult {
  const status: SessionProviderResult['status'] =
    doc.status === 'running' || doc.status === 'pending'
      ? 'failed'
      : doc.status;
  return {
    status,
    exitCode: doc.exitCode ?? 1,
    error: doc.error,
    providerSessionId: doc.providerSessionId,
    tokenUsage: doc.tokenUsage,
    costUsd: doc.costUsd,
    output: doc.output,
    // Note: transcript is not included here — it's in the transcripts book.
    // The babysitter writes it directly to SQLite.
  };
}

/**
 * Launch a detached babysitter process.
 *
 * Returns { chunks, result, processInfo } where:
 * - chunks: completes immediately (empty) — transcripts stream to SQLite
 * - result: polls sessions book for terminal status
 * - processInfo: polls SessionDoc for cancelMetadata (contains claude PID)
 */
export function launchDetached(
  config: SessionProviderConfig,
  opts?: DetachedLaunchOptions,
): {
  chunks: AsyncIterable<SessionChunk>;
  result: Promise<SessionProviderResult>;
  processInfo?: Promise<Record<string, unknown>>;
} {
  const babysitterPath = opts?.babysitterPath ?? resolveBabysitterPath();
  const pollIntervalMs = opts?.pollIntervalMs ?? POLL_INTERVAL_MS;
  const pollTimeoutMs = opts?.pollTimeoutMs ?? POLL_TIMEOUT_MS;
  const spawnFn = opts?.spawnFn ?? spawn;

  // Resolve sessions book lazily to avoid import-time guild() calls
  const getSessionsBook = (): ReadOnlyBook<SessionDoc> => {
    if (opts?.sessionsBook) return opts.sessionsBook;
    const stacks = guild().apparatus<StacksApi>('stacks');
    return stacks.readBook<SessionDoc>('animator', 'sessions');
  };
  const getWritableSessionsBook = (): Book<SessionDoc> => {
    const stacks = guild().apparatus<StacksApi>('stacks');
    return stacks.book<SessionDoc>('animator', 'sessions');
  };

  // Build babysitter config
  const babysitterConfig = buildBabysitterConfig(config, opts);

  // Compute the full authorized tool set for this session: every tool the
  // session was composed with, plus the two infrastructure tools it needs
  // to report its own lifecycle back to the guild.
  const authorizedTools = [
    ...(config.tools?.map((rt) => rt.definition.name) ?? []),
    'session-running',
    'session-record',
  ];

  // Pre-write a `pending` SessionDoc BEFORE spawning the babysitter. This
  // is the source of truth for the tool server's authorize callback: by
  // the time the babysitter's first HTTP call lands, the sessions book
  // already records the session and the tools it's allowed to call.
  //
  // The babysitter's `session-running` call will merge this doc into a
  // `running` one, preserving authorizedTools.
  //
  // Fire-and-forget — spawn must not block on this. In the worst case
  // the babysitter will retry its first HTTP call for up to 60s, which
  // is plenty of time for the SQLite write to land.
  (async () => {
    try {
      const sessions = getWritableSessionsBook();
      await sessions.put({
        id: config.sessionId,
        status: 'pending',
        startedAt: new Date().toISOString(),
        provider: 'claude-code',
        authorizedTools,
        ...(opts?.metadata ? { metadata: opts.metadata } : {}),
      });
    } catch (err) {
      console.warn(
        `[claude-code] Failed to pre-write pending session ${config.sessionId}: ${err instanceof Error ? err.message : err}`,
      );
    }
  })();

  // Spawn the babysitter as a detached process.
  // stdio: ['pipe', 'ignore', 'inherit'] — config via stdin, no stdout, stderr to parent
  //
  // In source mode (.ts babysitter), forward the parent's execArgv so that
  // --experimental-transform-types (and friends) reach the child. Without
  // this, node would try to load a .ts file as plain CommonJS and crash.
  const isSource = babysitterPath.endsWith('.ts');
  const nodeArgs = isSource
    ? [...process.execArgv, babysitterPath]
    : [babysitterPath];
  const proc = spawnFn(process.execPath, nodeArgs, {
    cwd: config.cwd,
    stdio: ['pipe', 'ignore', 'inherit'],
    detached: true,
    env: { ...process.env, ...config.environment },
  });

  // Write config to the babysitter's stdin, then close it.
  proc.stdin!.write(JSON.stringify(babysitterConfig));
  proc.stdin!.end();

  // Detach — guild doesn't wait for the babysitter.
  proc.unref();

  // Empty chunks — real-time output is via the transcripts book, not in-memory.
  const chunks: AsyncIterable<SessionChunk> = {
    [Symbol.asyncIterator]() {
      return {
        async next() {
          return { value: undefined as unknown as SessionChunk, done: true };
        },
      };
    },
  };

  // Result: poll sessions book for terminal status.
  const result = (async (): Promise<SessionProviderResult> => {
    try {
      const sessionsBook = getSessionsBook();
      const doc = await pollForTerminalStatus(
        sessionsBook,
        config.sessionId,
        pollIntervalMs,
        pollTimeoutMs,
      );
      return docToProviderResult(doc);
    } catch (err) {
      return {
        status: 'failed',
        exitCode: 1,
        error: `Detached session polling failed: ${err instanceof Error ? err.message : String(err)}`,
      };
    }
  })();

  // processInfo: poll for cancelMetadata (contains claude PID from babysitter).
  // Falls back to the babysitter's own PID.
  const processInfo = (async (): Promise<Record<string, unknown>> => {
    try {
      const sessionsBook = getSessionsBook();
      const info = await pollForProcessInfo(
        sessionsBook,
        config.sessionId,
        pollIntervalMs,
      );
      if (Object.keys(info).length > 0) return info;
    } catch {
      // Fall through to babysitter PID
    }
    // Fallback: return babysitter PID. Signals to the babysitter process group
    // leader (detached: true) can still reach claude via process group.
    return { pid: proc.pid };
  })();

  return { chunks, result, processInfo };
}

/**
 * The Animator — public types.
 *
 * These types form the contract between The Animator apparatus and all
 * callers (summon relay, nsg consult, etc.). No implementation details.
 *
 * See: docs/specification.md (animator)
 */

import type { AnimaWeave } from '@shardworks/loom-apparatus';
import type { ResolvedTool } from '@shardworks/tools-apparatus';

// ── Session chunks (streaming output) ────────────────────────────────

/** A chunk of output from a running session. */
export type SessionChunk =
  | { type: 'text'; text: string }
  | { type: 'tool_use'; tool: string }
  | { type: 'tool_result'; tool: string };

// ── Request / Result ─────────────────────────────────────────────────

export interface AnimateRequest {
  /**
   * Optional pre-generated session id. When provided, the Animator uses
   * this id instead of generating a new one. Used by summon() to make the
   * session id available on the handle before the Loom weave resolves.
   */
  sessionId?: string;
  /** The anima weave from The Loom (composed identity context). */
  context: AnimaWeave;
  /**
   * The work prompt — what the anima should do.
   * Passed directly to the session provider as the initial prompt.
   * This bypasses The Loom — it is not a composition concern.
   */
  prompt?: string;
  /**
   * Working directory for the session.
   * The session provider launches the AI process here.
   */
  cwd: string;
  /**
   * Optional conversation id to resume a multi-turn conversation.
   * If provided, the session provider resumes the existing conversation
   * rather than starting a new one.
   */
  conversationId?: string;
  /**
   * Caller-supplied metadata recorded alongside the session.
   * The Animator stores this as-is — it does not interpret the contents.
   */
  metadata?: Record<string, unknown>;
  /**
   * Enable streaming output. When true, the returned `chunks` iterable
   * yields output as the session produces it. When false (default), the
   * `chunks` iterable completes immediately with no items.
   *
   * Either way, the return shape is the same: `{ chunks, result }`.
   */
  streaming?: boolean;
  /**
   * Task-layer environment variables. Overrides the identity-layer
   * environment from the AnimaWeave when keys collide. Spread into the
   * spawned process environment.
   */
  environment?: Record<string, string>;
}

export interface SessionResult {
  /** Unique session id (generated by The Animator). */
  id: string;
  /** Terminal status. */
  status: 'completed' | 'failed' | 'timeout' | 'cancelled';
  /** When the session started (ISO-8601). */
  startedAt: string;
  /** When the session ended (ISO-8601). */
  endedAt: string;
  /** Wall-clock duration in milliseconds. */
  durationMs: number;
  /** Provider name (e.g. 'claude-code'). */
  provider: string;
  /** Numeric exit code from the provider process. */
  exitCode: number;
  /** Error message if failed. */
  error?: string;
  /** Conversation id (for multi-turn resume). */
  conversationId?: string;
  /** Session id from the provider (e.g. for --resume). */
  providerSessionId?: string;
  /** Token usage from the provider, if available. */
  tokenUsage?: TokenUsage;
  /** Cost in USD from the provider, if available. */
  costUsd?: number;
  /** Caller-supplied metadata, recorded as-is. */
  metadata?: Record<string, unknown>;
  /**
   * The final assistant text from the session.
   * Extracted by the Animator from the provider's transcript.
   * Useful for programmatic consumers that need the session's conclusion
   * without parsing the full transcript (e.g. the Spider's review collect step).
   */
  output?: string;
}

export interface TokenUsage {
  inputTokens: number;
  outputTokens: number;
  cacheReadTokens?: number;
  cacheWriteTokens?: number;
}

// ── Summon request ──────────────────────────────────────────────────

export interface SummonRequest {
  /**
   * The work prompt — what the anima should do.
   * Passed directly to the session provider as the initial prompt.
   */
  prompt: string;
  /**
   * The role to summon (e.g. 'artificer', 'scribe').
   * Passed to The Loom for context composition and recorded in session metadata.
   */
  role?: string;
  /**
   * Working directory for the session.
   * The session provider launches the AI process here.
   */
  cwd: string;
  /**
   * Optional conversation id to resume a multi-turn conversation.
   */
  conversationId?: string;
  /**
   * Additional metadata to record alongside the session.
   * Merged with auto-generated metadata (trigger: 'summon', role).
   */
  metadata?: Record<string, unknown>;
  /**
   * Enable streaming output. When true, the returned `chunks` iterable
   * yields output as the session produces it. When false (default), the
   * `chunks` iterable completes immediately with no items.
   */
  streaming?: boolean;
  /**
   * Task-layer environment variables. Overrides the identity-layer
   * environment from the AnimaWeave when keys collide. Spread into the
   * spawned process environment.
   */
  environment?: Record<string, string>;
}

// ── Animator API (the `provides` interface) ──────────────────────────

/** The return value from animate() and summon(). */
export interface AnimateHandle {
  /**
   * Session ID, available immediately after launch — before the session
   * completes. Callers that only need to know the session was launched
   * (e.g. quick engines returning `{ status: 'launched', sessionId }`)
   * can return without awaiting `result`.
   */
  sessionId: string;
  /**
   * Async iterable of output chunks from the session. When streaming is
   * disabled (the default), this iterable completes immediately with no
   * items. When streaming is enabled, it yields chunks as the session
   * produces output.
   */
  chunks: AsyncIterable<SessionChunk>;
  /**
   * Promise that resolves to the final SessionResult after the session
   * completes (or fails/times out) and the result is recorded to The Stacks.
   */
  result: Promise<SessionResult>;
}

export interface AnimatorApi {
  /**
   * Summon an anima — compose context via The Loom and launch a session.
   *
   * This is the high-level "make an anima do a thing" entry point.
   * Internally calls The Loom for context composition (passing the role),
   * then animate() for session launch and recording. The work prompt
   * bypasses the Loom and goes directly to the provider.
   *
   * Requires The Loom apparatus to be installed. Throws if not available.
   *
   * Auto-populates session metadata with `trigger: 'summon'` and `role`.
   *
   * Returns synchronously — the async work lives inside `result` and `chunks`.
   */
  summon(request: SummonRequest): AnimateHandle;

  /**
   * Animate a session — launch an AI process with the given context.
   *
   * This is the low-level entry point for callers that compose their own
   * AnimaWeave (e.g. The Parlour for multi-turn conversations).
   *
   * Records the session result to The Stacks before `result` resolves.
   *
   * Set `streaming: true` on the request to receive output chunks as the
   * session runs. When streaming is disabled (default), the `chunks`
   * iterable completes immediately with no items.
   *
   * Returns synchronously — the async work lives inside `result` and `chunks`.
   */
  animate(request: AnimateRequest): AnimateHandle;

  /**
   * Subscribe to a running session's output stream.
   *
   * Returns an AsyncIterable that replays all chunks already produced
   * (from session start) and then yields new chunks as they arrive.
   * Returns null if there is no active in-memory session with the given id
   * (i.e. the session is unknown, already completed, or started before this
   * process started).
   *
   * When the session ends, the iterable completes automatically.
   */
  subscribeToSession(sessionId: string): AsyncIterable<SessionChunk> | null;

  /**
   * Cancel a running session.
   *
   * Patches the SessionDoc to 'cancelled' with endedAt, durationMs, and
   * the optional reason in the error field. If cancelMetadata is available,
   * delegates to the provider's cancel() method to kill the process.
   *
   * Idempotent: if the session is already in a terminal state, returns the
   * existing SessionDoc without modification. Throws if the session ID
   * does not exist.
   *
   * Does NOT wait for the process to die — returns immediately after
   * patching and sending the kill signal.
   */
  cancel(sessionId: string, options?: { reason?: string }): Promise<SessionDoc>;
}

// ── Session provider interface ───────────────────────────────────────

/**
 * A session provider — pluggable backend that knows how to launch and
 * communicate with a specific AI system.
 *
 * Implemented as an apparatus plugin whose `provides` object satisfies
 * this interface. The Animator discovers the provider via guild config:
 * `guild.json["animator"]["sessionProvider"]` names the plugin id.
 *
 * The provider always returns `{ chunks, result }` — the same shape as
 * AnimateHandle. When `config.streaming` is true, the provider MAY yield
 * output chunks as the session runs. When false (or when the provider
 * does not support streaming), the chunks iterable completes immediately
 * with no items. The Animator does not branch on streaming capability —
 * it passes the flag through and trusts the provider to do the right thing.
 */
export interface AnimatorSessionProvider {
  /** Human-readable name (e.g. 'claude-code'). */
  name: string;

  /**
   * Launch a session. Returns `{ chunks, result }` synchronously.
   *
   * The `result` promise resolves when the AI process exits.
   * The `chunks` async iterable yields output when `config.streaming`
   * is true and the provider supports streaming; otherwise it completes
   * immediately with no items.
   *
   * Providers that don't support streaming simply ignore the flag and
   * return empty chunks — no separate method needed.
   */
  launch(config: SessionProviderConfig): {
    chunks: AsyncIterable<SessionChunk>;
    result: Promise<SessionProviderResult>;
    /**
     * Provider-specific process metadata for cross-process cancellation.
     * Resolves as soon as the process is spawned. The Animator persists the
     * resolved value as `cancelMetadata` on the SessionDoc.
     *
     * Optional — providers that don't support cancellation omit this.
     */
    processInfo?: Promise<Record<string, unknown>>;
  };

  /**
   * Cancel a running session using previously persisted process metadata.
   *
   * Called by the Animator with the cancelMetadata from the SessionDoc.
   * The provider interprets the metadata and kills the process.
   *
   * Optional — providers that don't support cancellation omit this.
   */
  cancel?(cancelMetadata: Record<string, unknown>): Promise<void>;
}

export interface SessionProviderConfig {
  /**
   * Pre-generated session id. The Animator generates this before calling
   * launch() so both sides share the same id. Providers that spawn detached
   * processes need this to correlate lifecycle events (session-running,
   * session-record) back to the Animator's session record.
   */
  sessionId: string;
  /** System prompt for the AI process. May be undefined if composition is not yet implemented. */
  systemPrompt?: string;
  /** Initial user message (e.g. writ description). */
  initialPrompt?: string;
  /** Model to use (from guild settings). */
  model: string;
  /** Optional conversation id for resume. */
  conversationId?: string;
  /** Working directory for the session. */
  cwd: string;
  /**
   * Enable streaming output. When true, the provider should yield output
   * chunks as the session produces them. When false (default), the chunks
   * iterable should complete immediately with no items.
   *
   * Providers that don't support streaming may ignore this flag.
   */
  streaming?: boolean;
  /**
   * Resolved tools for this session. When present, the provider should
   * configure an MCP server with these tool definitions.
   *
   * The Loom resolves role → permissions → tools via the Instrumentarium.
   * The Animator passes them through from the AnimaWeave.
   */
  tools?: ResolvedTool[];
  /**
   * Merged environment variables to spread into the spawned process.
   * The Animator merges identity-layer (weave) and task-layer (request)
   * variables before passing them here — task layer wins on collision.
   */
  environment?: Record<string, string>;
}

/** A single message from the NDJSON stream. Untyped — shape varies by provider. */
export type TranscriptMessage = Record<string, unknown>;

export interface SessionProviderResult {
  /** Exit status. */
  status: 'completed' | 'failed' | 'timeout' | 'cancelled';
  /** Numeric exit code from the process. */
  exitCode: number;
  /** Error message if failed. */
  error?: string;
  /** Provider's session id (e.g. for --resume). */
  providerSessionId?: string;
  /** Token usage, if the provider can report it. */
  tokenUsage?: TokenUsage;
  /** Cost in USD, if the provider can report it. */
  costUsd?: number;
  /**
   * The session's full transcript — array of NDJSON message objects.
   *
   * In attached mode, this is populated directly from the NDJSON stream.
   * In detached mode, the transcript is written to SQLite by the babysitter
   * and is available via `stacks.book('animator', 'transcripts').get(sessionId)`
   * rather than on this result object.
   */
  transcript?: TranscriptMessage[];
  /**
   * The final assistant text from the session.
   * Extracted from the last assistant message's text content blocks.
   * Undefined if the session produced no assistant output.
   */
  output?: string;
  /** Process signal name if the session was killed by signal (e.g. 'SIGTERM', 'SIGKILL'). */
  signal?: string;
}

// ── Stacks document type ─────────────────────────────────────────────

/**
 * The session document stored in The Stacks' `sessions` book.
 * Includes all SessionResult fields plus the `id` required by BookEntry.
 */
export interface SessionDoc {
  id: string;
  /**
   * Session status. Initially written as `'running'` when the session is
   * launched, then updated to a terminal status (`'completed'`, `'failed'`,
   * `'timeout'`, or `'cancelled'`) after the provider exits or cancel is called.
   * The `'running'` state is transient.
   * `SessionResult.status` only includes terminal states.
   */
  status: 'pending' | 'running' | 'completed' | 'failed' | 'timeout' | 'cancelled';
  startedAt: string;
  endedAt?: string;
  durationMs?: number;
  provider: string;
  exitCode?: number;
  error?: string;
  conversationId?: string;
  providerSessionId?: string;
  tokenUsage?: TokenUsage;
  costUsd?: number;
  metadata?: Record<string, unknown>;
  /** The final assistant text from the session. */
  output?: string;
  /**
   * Provider-owned opaque metadata for cross-process cancellation.
   * Written by the Animator from the provider's processInfo at session launch.
   * The Animator does not interpret this — it passes it back to the provider's
   * cancel() method when cancellation is requested.
   *
   * Shape is provider-specific:
   * - claude-code: { pid: number }
   * - future docker: { containerId: string }
   * - future remote: { jobId: string, host: string }
   */
  cancelMetadata?: Record<string, unknown>;
  /**
   * Tool names this session is authorized to call over the Tool HTTP API.
   *
   * Source of truth for the daemon's Stacks-backed authorize callback.
   * Pre-written by `launchDetached()` (or animate()) before the babysitter
   * is spawned, then preserved through subsequent updates.
   */
  authorizedTools?: string[];
  /** Index signature required by BookEntry. */
  [key: string]: unknown;
}

/**
 * The transcript document stored in The Stacks' `transcripts` book.
 * One record per session — 1:1 relationship with SessionDoc.
 */
export interface TranscriptDoc {
  /** Same as the session id. */
  id: string;
  /** Full NDJSON transcript from the session. */
  messages: TranscriptMessage[];
  /** Index signature required by BookEntry. */
  [key: string]: unknown;
}

// ── Animator config ──────────────────────────────────────────────────

/** Plugin configuration stored at guild.json["animator"]. */
export interface AnimatorConfig {
  /**
   * Plugin id of the apparatus that implements AnimatorSessionProvider.
   * The Animator looks this up via guild().apparatus() at animate-time.
   * Defaults to 'claude-code' if not specified.
   */
  sessionProvider?: string;
  /**
   * Run sessions in detached mode (babysitter survives guild restarts).
   * Defaults to true. Set to false to fall back to attached/inline sessions —
   * the escape hatch for debugging or if detached mode misbehaves.
   * Currently consulted by the claude-code provider.
   */
  detached?: boolean;
}

// Augment GuildConfig so `guild().guildConfig().animator` is typed without
// requiring a manual type parameter at the call site.
declare module '@shardworks/nexus-core' {
  interface GuildConfig {
    animator?: AnimatorConfig;
  }
}

/**
 * session-running tool — record initial "running" state for a detached session.
 *
 * Called by the session babysitter immediately after spawning claude.
 * Writes a SessionDoc with status: 'running' to the sessions book,
 * which fires CDC so the Laboratory observes session start.
 *
 * This replaces the in-process recordRunning() path for detached sessions.
 * The existing in-process path continues to work for non-detached sessions.
 *
 * See: docs/architecture/detached-sessions.md
 */

import { tool } from '@shardworks/tools-apparatus';
import { guild } from '@shardworks/nexus-core';
import { z } from 'zod';
import type { StacksApi } from '@shardworks/stacks-apparatus';
import type { SessionDoc } from '../types.ts';

export default tool({
  name: 'session-running',
  description: 'Record initial running state for a detached session',
  instructions:
    'Called by session babysitters to record that a detached session has started. ' +
    'Writes a SessionDoc with status "running" to the sessions book. ' +
    'Not intended for patron or anima use.',
  params: {
    sessionId: z.string().describe('The session ID (pre-generated by the Animator at dispatch time)'),
    startedAt: z.string().describe('ISO timestamp of session start'),
    provider: z.string().describe('Provider name (e.g. "claude-code")'),
    conversationId: z.string().optional().describe('For --resume sessions'),
    metadata: z.record(z.string(), z.unknown()).optional().describe('Session metadata (writId, engineId, etc.)'),
    cancelMetadata: z.record(z.string(), z.unknown()).optional().describe('Includes { pid } for cross-process cancellation'),
  },
  callableBy: 'anima',
  permission: 'write',
  handler: async (params) => {
    const stacks = guild().apparatus<StacksApi>('stacks');
    const sessions = stacks.book<SessionDoc>('animator', 'sessions');

    // Merge with any pre-existing doc (e.g. the `pending` record written by
    // launchDetached before the babysitter was spawned). Preserve
    // authorizedTools, existing metadata, and any other fields the caller
    // may not have passed.
    const existing = await sessions.get(params.sessionId);

    const doc: SessionDoc = {
      ...(existing ?? {}),
      id: params.sessionId,
      status: 'running',
      startedAt: existing?.startedAt ?? params.startedAt,
      provider: existing?.provider ?? params.provider,
      ...(params.conversationId ? { conversationId: params.conversationId } : {}),
      ...(params.metadata ? { metadata: { ...(existing?.metadata ?? {}), ...params.metadata } } : {}),
      ...(params.cancelMetadata
        ? { cancelMetadata: { ...(existing?.cancelMetadata ?? {}), ...params.cancelMetadata } }
        : {}),
    };

    await sessions.put(doc);

    return { ok: true, sessionId: params.sessionId };
  },
});

