          `[animator] DLQ drain failed: ${err instanceof Error ? err.message : err}`,
        );
      }
      try {
        await recoverOrphans(sessions);
      } catch (err) {
        console.warn(
          `[animator] Orphan recovery failed: ${err instanceof Error ? err.message : err}`,
        );
      }
    })();
  },
},

