 37→
 38→// ── Helpers ────────────────────────────────────────────────────────────
 39→
 40→function makeProviderConfig(overrides?: Partial<SessionProviderConfig>): SessionProviderConfig {
 41→  return {
 42→    sessionId: 'ses-test-001',
 43→    model: 'sonnet',
 44→    cwd: os.tmpdir(),
 45→    ...overrides,
 46→  };
 47→}
