    let callCount = 0;
    const book = {
      async get(id: string) {
        callCount++;
        if (callCount < 4) return doc;
        return terminalDoc;
      },
      async find() { return []; },
      async list() { return []; },
      async count() { return 0; },
    } as unknown as ReadOnlyBook<SessionDoc>;

    const config = makeProviderConfig({ cwd: tmpDir });
    const { processInfo, result } = launchDetached(config, {
