  });

  it('returns empty on timeout', async () => {
    const book = createMockSessionsBook(
      new Map([['ses-test-001', makeSessionDoc({ status: 'running' })]]),
    );

    const info = await pollForProcessInfo(book, 'ses-test-001', 50, 200);

