    const { result } = launchDetached(config, {
      babysitterPath: babysitterScript,
      guildToolUrl: 'http://127.0.0.1:7471',
      dbPath: path.join(tmpDir, 'nexus.db'),
      sessionsBook: book,
      pollIntervalMs: 50,
