        callCount++;
        if (callCount < 3) {
          return makeSessionDoc({ id, status: 'running' });
        }
        return makeSessionDoc({
          id,
          status: 'running',
          cancelMetadata: { pid: 99 },
        });
      },
      async find() { return []; },
